import { MakeLogicType, kea, key, listeners, path, props, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'
import posthog from 'posthog-js'

import api from 'lib/api'
import { organizationLogic } from 'scenes/organizationLogic'

import { LogExplanation } from './types'

export interface LogExploreAILogicProps {
    logUuid: string
    logTimestamp: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logExploreAILogicValues {
    dataProcessingAccepted: boolean
    explanation: LogExplanation | null
    explanationError: string | null
    explanationLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logExploreAILogicActions {
    loadExplanation: () => any
    loadExplanationFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadExplanationSuccess: (
        explanation: LogExplanation,
        payload?: any
    ) => {
        explanation: LogExplanation
        payload?: any
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logExploreAILogicMeta {
    key: string
    __keaTypeGenInternalSelectorTypes: {
        dataProcessingAccepted: (currentOrganization: null | import('~/types').OrganizationType) => boolean
    }
}

export type logExploreAILogicType = MakeLogicType<
    logExploreAILogicValues,
    logExploreAILogicActions,
    LogExploreAILogicProps,
    logExploreAILogicMeta
>

export const logExploreAILogic = kea<logExploreAILogicType>([
    props({} as LogExploreAILogicProps),
    key((props) => props.logUuid),
    path((key) => [
        'products',
        'logs',
        'frontend',
        'components',
        'LogsViewer',
        'LogDetailsModal',
        'logExploreAILogic',
        key,
    ]),

    selectors({
        dataProcessingAccepted: [
            () => [organizationLogic.selectors.currentOrganization],
            (currentOrganization: null | import('~/types').OrganizationType): boolean =>
                !!currentOrganization?.is_ai_data_processing_approved,
        ],
    }),

    reducers({
        explanationError: [
            null as string | null,
            {
                loadExplanation: () => null,
                loadExplanationFailure: (_, { error }) => error || 'Failed to generate explanation',
            },
        ],
    }),

    loaders(({ props, values }) => ({
        explanation: {
            __default: null as LogExplanation | null,
            loadExplanation: async (): Promise<LogExplanation> => {
                if (!values.dataProcessingAccepted) {
                    throw new Error('AI data processing must be approved before generating explanations')
                }
                return await api.logs.explain(props.logUuid, props.logTimestamp)
            },
        },
    })),

    listeners({
        loadExplanation: () => {
            posthog.capture('logs ai explanation requested')
        },
    }),
])
